import collections

class ShoppingOptimizer:
    def __init__(self, products):
        self.products = products
        self.offers = []

    def add_offer(self, offer_type, **kwargs):
        self.offers.append({'type': offer_type, **kwargs})

    def optimize_cart(self, cart_items):
        temp_cart = collections.Counter(cart_items)
        final_cost = 0.0

        while True:
            best_saving_this_round = 0.0
            best_action = None

            # Evaluate Bundle Offers
            for offer_idx, offer in enumerate(self.offers):
                if offer['type'] == 'BUNDLE_FIXED_PRICE':
                    bundle_items_needed = offer['items']
                    can_apply = True
                    for item, qty_needed in bundle_items_needed.items():
                        if temp_cart.get(item, 0) < qty_needed:
                            can_apply = False
                            break

                    if can_apply:
                        base_bundle_cost = sum(qty_needed * self.products.get(item, 0) for item, qty_needed in bundle_items_needed.items())
                        saving = base_bundle_cost - offer['bundle_price']

                        if saving > best_saving_this_round:
                            best_saving_this_round = saving
                            best_action = {
                                'type': 'bundle',
                                'offer': offer,
                                'cost_impact': offer['bundle_price']
                            }

            # Evaluate Item Quantity Fixed Price Offers
            for offer_idx, offer in enumerate(self.offers):
                if offer['type'] == 'ITEM_QUANTITY_FIXED_PRICE':
                    item_name = offer['item']
                    required_qty = offer['quantity']
                    total_fixed_price = offer['total_price']

                    if temp_cart.get(item_name, 0) >= required_qty:
                        base_cost_for_offer_qty = required_qty * self.products.get(item_name, 0)
                        saving = base_cost_for_offer_qty - total_fixed_price

                        if saving > best_saving_this_round:
                            best_saving_this_round = saving
                            best_action = {
                                'type': 'item_qty',
                                'offer': offer,
                                'cost_impact': total_fixed_price
                            }

            if best_saving_this_round > 0 and best_action is not None:
                final_cost += best_action['cost_impact']
                offer_applied = best_action['offer']

                if best_action['type'] == 'bundle':
                    for item, qty_needed in offer_applied['items'].items():
                        temp_cart[item] -= qty_needed
                        if temp_cart[item] == 0:
                            del temp_cart[item]
                elif best_action['type'] == 'item_qty':
                    item_name = offer_applied['item']
                    required_qty = offer_applied['quantity']
                    temp_cart[item_name] -= required_qty
                    if temp_cart[item_name] == 0:
                        del temp_cart[item_name]
            else:
                break

        # Process remaining items with percentage discounts or base prices
        items_to_process = list(temp_cart.keys())
        for item_name in items_to_process:
            if item_name not in temp_cart:
                continue

            qty_in_cart = temp_cart[item_name]
            base_price_per_item = self.products.get(item_name, 0)
            current_item_cost = qty_in_cart * base_price_per_item

            best_item_discount_cost = current_item_cost

            for offer in self.offers:
                if offer['type'] == 'ITEM_PERCENTAGE_DISCOUNT' and offer['item'] == item_name:
                    percentage_off = offer['percentage']
                    discounted_cost = qty_in_cart * base_price_per_item * (100 - percentage_off) / 100
                    if discounted_cost < best_item_discount_cost:
                        best_item_discount_cost = discounted_cost

            final_cost += best_item_discount_cost
            del temp_cart[item_name]

        for item, qty in temp_cart.items():
            final_cost += qty * self.products.get(item, 0)

        return round(final_cost, 2)
